// src/components/Intro.js
import React, { useEffect, useState } from 'react';
import './Intro.css';

export default function Intro({ onComplete }) {
  const [phase, setPhase] = useState('enter');

  useEffect(() => {
    const t1 = setTimeout(() => setPhase('zoom'), 800);
    const t2 = setTimeout(() => setPhase('fadeout'), 2300);

    // 🔥 ONLY notify parent — do NOT unmount here
    const t3 = setTimeout(() => {
      onComplete?.();
    }, 3400); // matches CSS timing

    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
      clearTimeout(t3);
    };
  }, [onComplete]);

  return (
    <div className={`intro-overlay intro-overlay--${phase}`}>
      <div className="intro-dark" />

      <div className={`intro-lens intro-lens--${phase}`}>
        <div className="intro-lens__inner">
          <img
            src="/assets/profile-pic.jpg"
            alt="Profile"
            className="intro-lens__photo"
          />
          <div className="intro-lens__ring intro-lens__ring--1" />
          <div className="intro-lens__ring intro-lens__ring--2" />
        </div>
        <div className="intro-lens__bevel" />
      </div>

      <div className={`intro-text intro-text--${phase}`}>
        <div className="intro-text__tl">
          <span className="intro-eyebrow">Hello, I'm</span>
          <h1 className="intro-name">
            Albertus<br /><em>Ivan Wijaya</em>
          </h1>
        </div>

        <div className="intro-text__br">
          <div className="intro-tagline">Software Developer</div>
          <div className="intro-tagline intro-tagline--sub">
            CS + Statistics @ UBC
          </div>
        </div>
      </div>
    </div>
  );
}
